#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

// Simple half2 structure for CPU simulation if not available
struct half2 {
    float x;
    float y;
};

inline float __float2half(float f) { return f; }
inline int __int2half_rd(int i) { return i; }

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template<>
inline half2 conv_int(const int i){ 
    half2 h;
    h.x = static_cast<float>(i);
    h.y = static_cast<float>(i);
    return h;
}

template<>
inline half2 mad(const half2 a, const half2 b, const half2 c){ 
    half2 res;
    res.x = a.x * b.x + c.x;
    res.y = a.y * b.y + c.y;
    return res;
}

template<>
inline bool equal(const half2 a, const half2 b){ 
    return (a.x == b.x) && (a.y == b.y);
}

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *g_data, long total_elements, long stride, long big_stride) {
    #pragma omp parallel
    {
        long num_threads = omp_get_num_threads();
        long thread_id = omp_get_thread_num();

        long block_size = (total_elements + num_threads - 1) / num_threads;
        long start_idx = thread_id * block_size;
        if (start_idx >= total_elements) return;
        long end_idx = start_idx + block_size;
        if (end_idx > total_elements) end_idx = total_elements;

        T tmps[granularity];

        for(long idx = start_idx; idx < end_idx; idx += stride) {
            for(int k=0; k<fusion_degree; k++){
                for(int j=0; j<granularity; j++){
                    long access_idx = idx + j*stride + k*big_stride;
                    if (access_idx < total_elements)
                        tmps[j] = g_data[access_idx];
                    else
                        tmps[j] = conv_int<T>(0);

                    int unroll_factor = TemperateUnroll ? 4 : 128;
                    (void)unroll_factor; // Avoid unused warning
                    for(int i=0; i<compute_iterations; i++){
                        tmps[j] = mad(tmps[j], tmps[j], seed);
                    }
                }

                T sum = conv_int<T>(0);
                for(int j=0; j<granularity; j+=2) {
                    if (j+1 < granularity)
                        sum = mad(tmps[j], tmps[j+1], sum);
                    else
                        sum = mad(tmps[j], conv_int<T>(0), sum);
                }

                if( equal(sum, conv_int<T>(-1)) ) {
                    long write_idx = idx + k*big_stride;
                    if (write_idx < total_elements)
                        g_data[write_idx] = sum;
                }
            }
        }
    }
}

double get_time() {
    return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
    const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    const int BLOCK_SIZE = 256;
    const int TOTAL_REDUCED_BLOCKS = reduced_grid_size/BLOCK_SIZE;
    if (TOTAL_REDUCED_BLOCKS <= 0) return;

    long total_elements = TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;
    if (total_elements > size) total_elements = size;

    benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >((short)1, (short*)cd, total_elements, BLOCK_SIZE, TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD);
}

int out_config = 1;

template<unsigned int compute_iterations>
void runbench(double *cd, long size, bool doHalfs){
    const long compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
    const int BLOCK_SIZE = 256;
    const int TOTAL_BLOCKS = compute_grid_size/BLOCK_SIZE;
    if (TOTAL_BLOCKS <= 0) return;

    const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
    const long long memoryoperations = size;

    long total_elements = TOTAL_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;
    if (total_elements > size) total_elements = size;
    long stride = BLOCK_SIZE;
    long big_stride = TOTAL_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;

    double start_time, end_time;
    float kernel_time_mad_sp, kernel_time_mad_dp, kernel_time_mad_hp, kernel_time_mad_int;

    start_time = get_time();
    benchmark_func< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, total_elements, stride, big_stride);
    end_time = get_time();
    kernel_time_mad_sp = (float)(end_time - start_time) * 1000.0f;

    start_time = get_time();
    benchmark_func< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0, cd, total_elements, stride, big_stride);
    end_time = get_time();
    kernel_time_mad_dp = (float)(end_time - start_time) * 1000.0f;

    kernel_time_mad_hp = 0.f;
    if( doHalfs ){
        half2 h_ones;
        h_ones.x = 1.0f;
        h_ones.y = 1.0f;
        start_time = get_time();
        benchmark_func< half2, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(h_ones, (half2*)cd, total_elements, stride, big_stride);
        end_time = get_time();
        kernel_time_mad_hp = (float)(end_time - start_time) * 1000.0f;
    }

    start_time = get_time();
    benchmark_func< int, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true >(1, (int*)cd, total_elements, stride, big_stride);
    end_time = get_time();
    kernel_time_mad_int = (float)(end_time - start_time) * 1000.0f;

    printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        compute_iterations,
        ((double)computations)/((double)memoryoperations*sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
        ((double)2*computations)/((double)memoryoperations*sizeof(half2)),
        kernel_time_mad_hp,
        ((double)2*computations)/kernel_time_mad_hp*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(half2))/kernel_time_mad_hp*1000./(1000.*1000.*1000.),
        ((double)computations)/((double)memoryoperations*sizeof(int)),
        kernel_time_mad_int,
        ((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
        ((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

